let exp = DateTime.now().timestamp() + 86400
let token = jwt.encode({ "sub": "ada", "exp": "{exp}" }, SECRET)
match jwt.decode(token, SECRET) {
Ok(claims) => process(claims),
Err(e) => return 401 { "error": "{e}" },
}

