@authenticated
@post("/auth/logout")
async fn logout(db: DbConn, user: User) -> Map<Str, Bool> {
auth.blacklist(db, user.jti, user.exp).await?
return { "ok": true }
}
@cron("0 0 3 * * *") // 3 AM diario
async fn cleanup_blacklist(db: DbConn) {
auth.cleanup_expired(db).await
}

